import { Component, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { RouterModule } from '@angular/router';

export type ChildVm = {
  id: string;
  name: string;
  level: string;
  avatarUrl: string;
};

export type ProgressVm = {
  courseId: string;
  courseTitle: string;
  progress: number;
  lastAccess: string;
};

export type SessionVm = {
  id: string;
  title: string;
  childName: string;
  scheduledAt: string;
};

@Component({
  selector: 'app-parent-dashboard',
  standalone: true,
  imports: [CommonModule, RouterModule],
  templateUrl: './parent-dashboard.component.html',
  styleUrls: ['./parent-dashboard.component.scss']
})
export class ParentDashboardComponent {
  isLoading = signal(true);

  parentName = signal('Mme Fatima');

  children = signal<ChildVm[]>([
    { id: 'ch1', name: 'Youssef', level: '2ème année', avatarUrl: '' },
    { id: 'ch2', name: 'Sofia', level: '4ème année', avatarUrl: '' }
  ]);

  selectedChildId = signal('ch1');

  progress = signal<ProgressVm[]>([
    { courseId: 'c1', courseTitle: 'Algèbre — Bases et exercices', progress: 35, lastAccess: '2026-03-20' },
    { courseId: 'c2', courseTitle: 'Physique — Mécanique', progress: 12, lastAccess: '2026-03-19' },
    { courseId: 'c3', courseTitle: 'Français — Expression écrite', progress: 58, lastAccess: '2026-03-20' }
  ]);

  upcomingSessions = signal<SessionVm[]>([
    { id: 's1', title: 'Correction du devoir de maths', childName: 'Youssef', scheduledAt: '2026-03-22T14:00:00' },
    { id: 's2', title: 'Physique — Cinématique', childName: 'Sofia', scheduledAt: '2026-03-23T10:00:00' }
  ]);

  stats = signal({
    avgProgress: 35,
    totalCourses: 6,
    avgScore: 72,
    sessionsThisWeek: 4
  });

  constructor() {
    setTimeout(() => this.isLoading.set(false), 600);
  }

  selectChild(id: string) {
    this.selectedChildId.set(id);
  }

  getChildInitial(name: string): string {
    return name.charAt(0);
  }
}
<div class="min-h-screen bg-[#F8F9FA] py-8">
  <div class="mx-auto w-full max-w-7xl px-4">
    <!-- Loading -->
    <div *ngIf="isLoading()" class="flex items-center justify-center py-20">
      <div class="h-12 w-12 animate-spin rounded-full border-4 border-gray-200 border-t-[#1A73E8]"></div>
    </div>

    <!-- Content -->
    <div *ngIf="!isLoading()">
      <!-- Header -->
      <div class="mb-8 overflow-hidden rounded-2xl border border-gray-200 bg-white p-6 shadow-sm">
        <div class="flex flex-col gap-4 sm:flex-row sm:items-center sm:justify-between">
          <div>
            <h1 class="text-2xl font-bold text-gray-900 sm:text-3xl">
              Bonjour, {{ parentName() }} !
            </h1>
            <p class="mt-1 text-gray-600">Suivez la progression de vos enfants</p>
          </div>
        </div>
      </div>

      <!-- Children Selector -->
      <div class="mb-6 flex gap-4 overflow-x-auto pb-2">
        <button
          *ngFor="let child of children()"
          (click)="selectChild(child.id)"
          class="flex items-center gap-3 rounded-xl border p-3 transition"
          [class]="selectedChildId() === child.id ? 'border-[#1A73E8] bg-[#1A73E8]/5' : 'border-gray-200 bg-white hover:border-gray-300'">
          <div class="flex h-10 w-10 items-center justify-center rounded-full bg-gradient-to-br from-[#1A73E8] to-[#FF6D00] text-white font-semibold">
            {{ getChildInitial(child.name) }}
          </div>
          <div class="text-left">
            <p class="font-medium text-gray-900">{{ child.name }}</p>
            <p class="text-xs text-gray-500">{{ child.level }}</p>
          </div>
        </button>
      </div>

      <!-- Stats Cards -->
      <div class="mb-8 grid gap-4 sm:grid-cols-2 lg:grid-cols-4">
        <div class="rounded-2xl border border-gray-200 bg-white p-5 shadow-sm">
          <p class="text-sm text-gray-500">Progression moyenne</p>
          <p class="mt-1 text-3xl font-bold text-[#1A73E8]">{{ stats().avgProgress }}%</p>
        </div>
        <div class="rounded-2xl border border-gray-200 bg-white p-5 shadow-sm">
          <p class="text-sm text-gray-500">Cours actifs</p>
          <p class="mt-1 text-3xl font-bold text-gray-900">{{ stats().totalCourses }}</p>
        </div>
        <div class="rounded-2xl border border-gray-200 bg-white p-5 shadow-sm">
          <p class="text-sm text-gray-500">Note moyenne</p>
          <p class="mt-1 text-3xl font-bold text-[#34A853]">{{ stats().avgScore }}%</p>
        </div>
        <div class="rounded-2xl border border-gray-200 bg-white p-5 shadow-sm">
          <p class="text-sm text-gray-500">Sessions cette semaine</p>
          <p class="mt-1 text-3xl font-bold text-gray-900">{{ stats().sessionsThisWeek }}</p>
        </div>
      </div>

      <div class="grid gap-6 lg:grid-cols-2">
        <!-- Progression des cours -->
        <div class="rounded-2xl border border-gray-200 bg-white p-6 shadow-sm">
          <h2 class="mb-4 text-lg font-semibold text-gray-900">Progression des cours</h2>
          <div class="space-y-4">
            <div *ngFor="let p of progress()" class="rounded-xl border border-gray-200 p-4">
              <div class="mb-2 flex items-center justify-between">
                <h3 class="font-medium text-gray-900">{{ p.courseTitle }}</h3>
                <span class="text-sm text-gray-500">{{ p.progress }}%</span>
              </div>
              <div class="h-2 w-full overflow-hidden rounded-full bg-gray-100">
                <div class="h-full rounded-full bg-gradient-to-r from-[#1A73E8] to-[#FF6D00] transition-all" [style.width.%]="p.progress"></div>
              </div>
              <p class="mt-2 text-xs text-gray-400">Dernière activité: {{ p.lastAccess | date:'dd/MM/yyyy' }}</p>
            </div>
          </div>
        </div>

        <!-- Sessions à venir -->
        <div class="rounded-2xl border border-gray-200 bg-white p-6 shadow-sm">
          <h2 class="mb-4 text-lg font-semibold text-gray-900">Sessions live à venir</h2>
          <div class="space-y-3">
            <div *ngFor="let session of upcomingSessions()" class="flex items-center justify-between rounded-xl border border-gray-200 p-4">
              <div>
                <h3 class="font-medium text-gray-900">{{ session.title }}</h3>
                <p class="text-sm text-gray-500">Pour: {{ session.childName }}</p>
                <p class="text-xs text-gray-400">{{ session.scheduledAt | date:'dd/MM/yyyy HH:mm' }}</p>
              </div>
              <button class="rounded-lg border border-[#1A73E8] px-3 py-1.5 text-sm font-medium text-[#1A73E8] hover:bg-[#1A73E8]/5">
                Détails
              </button>
            </div>
          </div>
        </div>
      </div>
    </div>
  </div>
</div>
